pub const LoomPcsValue = struct { name: []const u8, value: [6]u32 };
pub const LoomPcsSlot = struct { name: []const u8, tree_idx: u32, poly_idx: u32, rail: PcsRail };
pub const LoomPcsPath = struct { leaf_idx: u32, siblings: []const [8]u32 };
pub const LoomPcsLayer = struct {
    rail: PcsRail,
    leaf_p_base: u32 = 0,
    leaf_q_base: u32 = 0,
    leaf_p_ext: [6]u32 = .{ 0, 0, 0, 0, 0, 0 },
    leaf_q_ext: [6]u32 = .{ 0, 0, 0, 0, 0, 0 },
    path: LoomPcsPath,
};
pub const LoomPcsQuery = struct { layers: []const LoomPcsLayer };
pub const LoomPcsSampling = struct {
    base_pairs: []const [2]u32 = &.{},
    ext_pairs: []const [2][6]u32 = &.{},
    path: LoomPcsPath,
};
pub const LoomPcsCase = struct {
    label: []const u8,
    n: u32,
    d: u32,
    num_queries: u32,
    num_rounds: u32,
    num_fs_rounds: u32,
    initial_challenge_bindings: []const u32,
    fs_round_root_indices: []const []const u32,
    fs_challenge_digests: []const [8]u32,
    zeta_root_indices: []const u32,
    zeta_digest: [8]u32,
    zeta: [6]u32,
    alpha_deep_digest: [8]u32,
    alpha_deep: [6]u32,
    fri_fold_digests: []const [8]u32,
    query_digests: []const [8]u32,
    query_positions: []const u32,
    level_ds: []const u32,
    tree_sizes: []const u32,
    roots: []const [8]u32,
    deep_quotient_commitment: []const [8]u32,
    fri_roots: []const [8]u32,
    final_poly_ext: []const [6]u32,
    values_at_zeta: []const LoomPcsValue,
    col_slots: []const LoomPcsSlot,
    air_chunk_slots: []const LoomPcsSlot,
    dq_eval_points: []const []const [6]u32,
    dq_column_names: []const []const []const []const u8,
    dq_column_keys: []const []const []const []const u8,
    dq_air_chunks: []const []const []const u8,
    queries: []const LoomPcsQuery,
    level_queries: []const []const LoomPcsLayer,
    point_samplings: []const []const LoomPcsSampling,
};

